// Phase 1 uses this as local seed; production data lives in Supabase (see CRM_SETUP.md).

export type PipelineStatus =
  | "New" | "Contacted" | "Engaged" | "Qualified" | "Proposal" | "Won" | "Lost";

export const PIPELINE_STATUSES: PipelineStatus[] = [
  "New", "Contacted", "Engaged", "Qualified", "Proposal", "Won", "Lost",
];

export type Readiness = "ready" | "partial" | "thin";

// How the company applies product. Drives map/marker classification.
export type OperatorType = "ground" | "aerial" | "drone" | "";

export interface Lead {
  id: string;
  name: string;
  dba: string;
  contact: string;
  aerial: boolean;        // holds a manned aerial pest-applicator license (CDA)
  codes: string[];        // CDA ag categories held (101/102/103)
  phone: string;
  email: string;
  website: string;
  city: string;
  county: string;
  state: string;
  zip: string;
  lat: number | null;
  lng: number | null;
  employees: number | string | "";
  revenue: string;
  status: PipelineStatus;
  readiness: Readiness;
  source: string;             // "CDA-CO" | "AgriSprayDrones" | ...
  operatorType: OperatorType; // ground / aerial / drone
  services: string[];         // e.g. ["Row Crop","Chemical","Pasture"]
  facebook: string;
  instagram: string;
}

